class Document:
    def __init__(self, text, size=10, color='black'):
        self.text = text
        self.size = size
        self.color = color

    def render(self):
        return f'{self.text}({self.size},{self.color})'


class RichDoc(Document):
    def __init__(self, text, size=14, **kwargs):
        # BUG: kwargs may already carry 'size', then we pass it again
        super().__init__(text, size=size, **kwargs)
        self.rich = True


def create_rich(**cfg):
    return RichDoc('title', **cfg)


def main():
    doc = create_rich(color='red', size=12)
    print(doc.render())


if __name__ == '__main__':
    main()
